use std::collections::{HashMap, HashSet, VecDeque};

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut adj: Vec<Vec<usize>> = vec![vec![]; c + 1];
    for conn in connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    // Build the connected components
    let mut component_id = vec![0; c + 1];
    let mut current_id = 0;
    for i in 1..=c {
        if component_id[i] == 0 {
            current_id += 1;
            let mut queue = VecDeque::new();
            queue.push_back(i);
            component_id[i] = current_id;
            while let Some(u) = queue.pop_front() {
                for &v in &adj[u] {
                    if component_id[v] == 0 {
                        component_id[v] = current_id;
                        queue.push_back(v);
                    }
                }
            }
        }
    }

    // Group nodes by component_id
    let mut components: HashMap<usize, Vec<usize>> = HashMap::new();
    for i in 1..=c {
        components.entry(component_id[i]).or_default().push(i);
    }

    // For each component, maintain a BTreeSet of online nodes
    let mut online: Vec<bool> = vec![true; c + 1];
    let mut component_min_online: HashMap<usize, std::collections::BTreeSet<usize>> = HashMap::new();
    for (&id, nodes) in &components {
        let set: std::collections::BTreeSet<_> = nodes.iter().cloned().collect();
        component_min_online.insert(id, set);
    }

    let mut result = Vec::new();
    for query in queries {
        let t = query[0];
        let x = query[1] as usize;
        if t == 1 {
            // Query type 1
            if online[x] {
                result.push(x as i64);
            } else {
                let cid = component_id[x];
                if let Some(set) = component_min_online.get_mut(&cid) {
                    if let Some(&min_node) = set.iter().next() {
                        result.push(min_node as i64);
                    } else {
                        result.push(-1);
                    }
                } else {
                    result.push(-1);
                }
