use std::collections::{HashMap, HashSet, VecDeque};

struct UnionFind {
    parent: Vec<usize>,
    size: Vec<usize>,
}

impl UnionFind {
    fn new(n: usize) -> Self {
        let mut parent = vec![0; n];
        let mut size = vec![1; n];
        for i in 0..n {
            parent[i] = i;
        }
        UnionFind { parent, size }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            if self.size[root_x] < self.size[root_y] {
                self.parent[root_x] = root_y;
                self.size[root_y] += self.size[root_x];
            } else {
                self.parent[root_y] = root_x;
                self.size[root_x] += self.size[root_y];
            }
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut uf = UnionFind::new(c + 1); // 1-based indexing
    for conn in connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        uf.union(u, v);
    }

    // Build a map from root to the set of nodes in the component
    let mut components: HashMap<usize, Vec<usize>> = HashMap::new();
    for i in 1..=c {
        let root = uf.find(i);
        components.entry(root).or_default().push(i);
    }

    // For each component, maintain a BinaryHeap (min-heap) of online nodes
    let mut online: HashSet<usize> = (1..=c).collect();
    let mut component_min_online: HashMap<usize, VecDeque<usize>> = HashMap::new();
    for (&root, nodes) in components.iter() {
        let mut sorted_nodes = nodes.clone();
        sorted_nodes.sort();
        let mut deque = VecDeque::new();
        for &node in &sorted_nodes {
            deque.push_back(node);
        }
        component_min_online.insert(root, deque);
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1] as usize;
        let root = uf.find(x);

        if query_type == 1 {
            if online.contains(&x) {
                result.push(x as i64);
            } else {
                let deque = component_min_online.get_mut(&root).unwrap();
                let mut found = None;
                while let Some(node) = deque.front() {
                    if online.contains(node) {
                        found = Some(*node);
                        break;
                    } else {
                        deque.pop_front();
                    }
                }
                if let Some(min_node) = found {
                    result.push(min_node as i64);
                } else {
                    result.push(-1);
                }
            }
        } else if query_type == 2 {
            online.remove(&x);
        }
    }

    result
}
